r = redis.Redis(host='localhost', port=6379, db=0)

@app.route('/set_session', methods=['POST'])
def set_session():
    session['username'] = request.form['username']
    r.set(session['id'], session['username'])
    return 'Session set'

@app.route('/get_session')
def get_session():
    id = session['id']
    username = r.get(id)
    if username is None:
        username = "Guest"
    return username

